{
  "title": "Guitar Basics for Beginners: Rizzing with Rhythm",
  "description": "This course is designed for complete beginners who want to learn guitar skills to impress and connect with others. The focus will be on foundational techniques, popular songs, and building confidence in playing.",
  "modules": [
    {
      "id": "1",
      "title": "Getting Started with Your Guitar",
      "description": "Learn the parts of the guitar, how to hold it properly, and basic tuning techniques. Understand the importance of posture and hand positioning."
    },
    {
      "id": "2",
      "title": "Essential Chords and Strumming Patterns",
      "description": "Explore fundamental chords and simple strumming patterns that will allow you to play a variety of songs. Practice transitioning between chords smoothly."
    },
    {
      "id": "3",
      "title": "Playing Popular Songs to Impress",
      "description": "Learn to play a selection of popular songs that are easy to master and will help you showcase your skills. Focus on songs that resonate with your audience."
    },
    {
      "id": "4",
      "title": "Building Confidence and Performance Skills",
      "description": "Develop your stage presence and performance techniques. Practice playing in front of others and learn tips for engaging with your audience effectively."
    }
  ]
}
